// Source JSX:
const el = (
  <p>
    Hello   world
  </p>
);

// What the compiler sees:
// Line 1: "  Hello   world  " → trimmed of leading/trailing whitespace
// Multiple spaces collapse → single space in the text node
// Leading newline (after <p>) → removed
// Trailing newline (before </p>) → removed

// Compiled result (equivalent):
const el = React.createElement('p', null, 'Hello world');
// Renders: "Hello world" — NOT "  Hello   world  "

// Source:
<p>
  <strong>Name:</strong>
  Alice
</p>
// Renders: "Name:Alice" — no space!
// The newline between </strong> and Alice is stripped

// Fix 1: put on the same line
<p><strong>Name:</strong> Alice</p>
// Renders: "Name: Alice" — the literal space before Alice is kept

// Fix 2: explicit space expression
<p><strong>Name:</strong>{' '}Alice</p>
// Renders: "Name: Alice" — the {' '} inserts a literal space text node

// Fix 3: use CSS (margin or flex gap) instead of text spaces
<p>
  <strong style={{ marginRight: '4px' }}>Name:</strong>
  Alice
</p>

// Source:
<div>
  <Button>A</Button>

  <Button>B</Button>
</div>

// Rendered DOM:
// <div>
//   <button>A</button>
//   <button>B</button>
// </div>
// No space between buttons — blank line removed

// To add visual spacing, use CSS margin/gap, not blank lines

// Between elements:
<p>
  <Icon />
  {' '}
  Click here
</p>
// Renders: "[icon] Click here"

// Between dynamic values:
<span>
  {firstName}
  {' '}
  {lastName}
</span>
// Renders: "John Smith" with a space between

// Same line: space before "or" is preserved
<p>Already have an account? <a href="/login">Log in</a></p>
// Renders: "Already have an account? Log in"

// Multi-line: space would be lost
<p>
  Already have an account?
  <a href="/login">Log in</a>
</p>
// Renders: "Already have an account?Log in" — missing space!

// Non-breaking space — prevents line-breaking between words
<abbr title="World Wide Web">W&nbsp;W&nbsp;W</abbr>

// Em dash — typographic separator
<p>React{'—'}a UI library</p>
// or as entity:
<p>React&mdash;a UI library</p>

// Copyright symbol
<footer>Copyright &copy; 2024 Deiva</footer>

// Note: JSX does not process HTML entity names like &amp; inside expressions {}
// Entities only work in literal JSX text, not in {} expressions

function PathDisplay({ segments }) {
  // Build the path string with controlled separators
  const path = segments.join(' / ');
  return <code>{path}</code>;
}

// Or inline:
<p>{`Page ${page} of ${total}`}</p>
// Space around "of" is controlled by the template literal

// Quoted string attribute — exact value (no JSX whitespace rules)
<input placeholder="Enter your name" />
// placeholder = "Enter your name" — exact, no trimming

// Expression attribute — the string passes through as-is
<input placeholder={"Enter your name"} />
// Same result

// Multi-line quoted attribute — JSX DOES trim here
<input
  placeholder="  Enter  your  name  "
/>
// placeholder = "  Enter  your  name  " — NOT trimmed
// Attribute values do not apply line-based whitespace rules
// (because they are already a single logical token)

// Dynamic attribute built from template literal
<input placeholder={`Search ${category}...`} />
// Spaces inside the template literal are preserved exactly

function CodeSample({ code }) {
  return <pre>{code}</pre>;
  // Newlines, indentation, and multiple spaces in `code` are all preserved
  // because <pre> tells the browser to render whitespace literally
}

// Using a string template for inline code samples:
function Example() {
  const sample = `function add(a, b) {
  return a + b;
}`;
  return <pre>{sample}</pre>;
}

// React's className for syntax highlighting:
<pre>
  <code className="language-js">{sourceCode}</code>
</pre>

function MarkdownOutput({ html }) {
  // html is a sanitized HTML string from a markdown renderer
  return (
    <div
      className="prose"
      dangerouslySetInnerHTML={{ __html: html }}
    />
  );
  // Whitespace in `html` is preserved — it's injected directly as innerHTML
}

function Tooltip({ children }) {
  // If children is a text node, it has already been whitespace-normalized by JSX
  console.log(children); // 'Click here' (no extra spaces even if you wrote them in JSX)
  return <span data-tip={String(children)}>{children}</span>;
}

// Usage:
<Tooltip>Click  here</Tooltip>
// children = "Click here" (spaces collapsed by JSX compiler)

// No separator between list items:
function TagList({ tags }) {
  return (
    <div>
      {tags.map(tag => <span key={tag} className="tag">{tag}</span>)}
    </div>
  );
  // Renders: <span>react</span><span>jsx</span><span>hooks</span>
  // No space between — use CSS gap or margin instead
}

// If you genuinely need comma-separated inline text:
function CommaSeparated({ items }) {
  return (
    <p>
      {items.map((item, i) => (
        <span key={item}>
          {item}{i < items.length - 1 ? ', ' : ''}
        </span>
      ))}
    </p>
  );
}

// Numbers render as text
<p>Items: {42}</p>          // "Items: 42"
<p>Price: {9.99}</p>        // "Price: 9.99"
<p>Score: {0}</p>           // "Score: 0"

// Booleans render nothing
<p>{true}</p>               // renders <p></p> — nothing visible
<p>{false}</p>              // renders <p></p>
<p>{Boolean(1)}</p>         // renders <p></p> — same

// null and undefined render nothing
<p>{null}</p>               // renders <p></p>
<p>{undefined}</p>          // renders <p></p>

// Empty string renders nothing visible
<p>{''}</p>                 // renders <p></p> (empty p tag)

// Arrays render their items concatenated
<p>{[1, 2, 3]}</p>         // renders "123" — no separator!
<p>{[1, ', ', 2, ', ', 3]}</p>  // renders "1, 2, 3"

// Objects cause an error — React can't render objects as children
// <p>{someObject}</p> → "Objects are not valid as a React child"
// Fix: JSON.stringify(someObject) or pick a specific property

// Pattern 1: template literal in {} — the clearest for complex text
function Greeting({ name, count }) {
  return <p>{`Hello, ${name}! You have ${count} notifications.`}</p>;
}

// Pattern 2: JSX string with space at the end of adjacent text
<p>Hello, <strong>world</strong> — welcome back.</p>
// The space before em-dash is in the literal JSX text

// Pattern 3: array of strings and elements
function BreadcrumbItem({ segments }) {
  return (
    <nav>
      {segments.flatMap((seg, i) => [
        i > 0 && <span key={`sep-${i}`} aria-hidden="true"> / </span>,
        <a key={seg.href} href={seg.href}>{seg.label}</a>
      ]).filter(Boolean)}
    </nav>
  );
}

// Pattern 4: helper that formats text
function formatCount(n, noun) {
  return `${n} ${noun}${n !== 1 ? 's' : ''}`;
}
<p>{formatCount(3, 'item')}</p>  // "3 items"
<p>{formatCount(1, 'item')}</p>  // "1 item"

// User input: '<script>alert("xss")</script>'
function Comment({ text }) {
  return <p>{text}</p>;
  // JSX renders: &lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;
  // Displayed as literal text, not executed HTML
}

// To render HTML from a trusted source (e.g. sanitized markdown):
function RichText({ html }) {
  return (
    <div
      dangerouslySetInnerHTML={{ __html: sanitize(html) }}
    />
  );
}

// NEVER do this with unsanitized user input:
<div dangerouslySetInnerHTML={{ __html: userInput }} />
// This is exactly the XSS attack vector React is designed to prevent

// Unicode characters work in JSX source files (UTF-8)
<p>Olá, mundo! こんにちは Привет</p>

// RTL text — set the dir attribute
<p dir="rtl" lang="ar">مرحبا بالعالم</p>

// Combining text and markup from a translation system
// Avoid dangerouslySetInnerHTML for user-visible i18n strings
// Use a component-based approach instead:
function Trans({ i18nKey, values }) {
  const template = t(i18nKey); // "Hello, {name}!"
  const parts = template.split(/(\{[^}]+\})/);
  return (
    <span>
      {parts.map((part, i) => {
        const match = part.match(/^\{(.+)\}$/);
        return match ? values[match[1]] : part;
      })}
    </span>
  );
}
<Trans i18nKey="greeting" values={{ name: <strong>Alice</strong> }} />

function AutoWidthInput({ value, onChange }) {
  const hiddenRef = useRef(null);
  const [width, setWidth] = useState('auto');

  useEffect(() => {
    // Measure text width from a hidden span containing the actual value
    // The DOM already has whitespace-normalized text
    if (hiddenRef.current) {
      setWidth(hiddenRef.current.offsetWidth + 4); // +4 for cursor
    }
  }, [value]);

  return (
    <>
      <span
        ref={hiddenRef}
        style={{ visibility: 'hidden', position: 'absolute', whiteSpace: 'pre' }}
      >
        {value || ' '}
      </span>
      <input
        value={value}
        onChange={onChange}
        style={{ width }}
      />
    </>
  );
}
